import { motion } from "framer-motion";
import { Link } from "react-router-dom";
// import ContactDetails from "../components/contact/ContactDetails";
// import ContactForm from "../components/contact/ContactForm";

const Contact = () => {
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{
        ease: "easeInOut",
        duration: 0.5,
        delay: 0.1,
      }}
      className="container mx-auto flex flex-col-reverse lg:flex-row py-5 lg:py-10 lg:mt-10"
    >
      <div className="container mx-auto">
        <div className="text-center">
          <p className="font-general-medium text-2xl sm:text-4xl mb-1 text-ternary-dark dark:text-ternary-light">
            Halaman tidak ditemukan
          </p>
          <p className="font-general-medium text-xl sm:text-xl mt-2 mb-1 text-ternary-dark dark:text-ternary-light">
            Kembali ke &#160;
            <Link to="/">
              <button
                class="inline-flex items-center justify-center px-4 py-2 text-base font-medium leading-6  whitespace-no-wrap bg-blue-600 border border-blue-700 rounded-md shadow-sm hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                data-rounded="rounded-md"
                data-primary="blue-600"
                data-primary-reset="{}"
              >
                Halaman Utama
              </button>
            </Link>
          </p>
        </div>
      </div>
    </motion.div>
  );
};

export default Contact;
